parameters.jsCode:
// Generate summary of the WhatsApp message sent
const messageData = $input.all()[0].json;
const geminiResponse = $('Generate Message with Gemini').item.json;

// Extract message from Gemini response
const messageText = geminiResponse.candidates[0].content.parts[0].text;

const summary = `WhatsApp message sent to ${messageData.name || 'customer'}.

Phone: ${messageData.phoneNumber}
Email: ${messageData.email || 'Not provided'}
Reason: ${messageData.reason || 'General inquiry'}

Message sent:
${messageText}

Status: Message sent successfully via WhatsApp.

Next steps: Customer can reply via WhatsApp, and you can continue the conversation.`;

return {
  messageId: messageData.messageId || `msg_${Date.now()}`,
  phoneNumber: messageData.phoneNumber,
  name: messageData.name,
  email: messageData.email,
  reason: messageData.reason,
  message: messageText,
  summary: summary,
  status: 'sent',
  timestamp: new Date().toISOString()
};
